import{_ as t,o as a,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Scalers Reference","description":"","frontmatter":{},"headers":[],"relativePath":"scalers/reference.md","filePath":"scalers/reference.md"}'),r={name:"scalers/reference.md"};function i(s,e,n,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="scalers-reference" tabindex="-1"><i class="ph ph-sliders"></i> Scalers Reference <a class="header-anchor" href="#scalers-reference" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; Scalers Reference&quot;">​</a></h1><p>Web Adaptive Performance includes a suite of specialized Scalers (optimization modules). The Indexer automatically selects which Scaler to deploy based on its <code>Visual Impact</code> and the current Bottleneck type (<code>Target</code>: CPU or GPU).</p><h2 id="compatibility-matrix" tabindex="-1">Compatibility Matrix <a class="header-anchor" href="#compatibility-matrix" aria-label="Permalink to &quot;Compatibility Matrix&quot;">​</a></h2><p>Below is the compatibility matrix and a description of all available modules.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Scaler</th><th style="text-align:left;">Pipeline</th><th style="text-align:left;">Target</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduces render resolution, radically decreasing the load on GPU Fillrate. <em>See details below.</em></td></tr><tr><td style="text-align:left;"><strong>Shadows Quality</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Progressively disables shadows.<br>In <strong>URP</strong>, it first disables soft shadows, then shadows from additional lights, and finally the main shadows.<br>In <strong>BiRP</strong>, it switches shadows to <code>Hard Only</code> mode before disabling them completely.</td></tr><tr><td style="text-align:left;"><strong>Shadow Cascades</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU/GPU</td><td style="text-align:left;">Reduces the number of shadow cascades. Decreases CPU Draw Calls and GPU load.</td></tr><tr><td style="text-align:left;"><strong>Shadow Distance</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Shortens the shadow draw distance.</td></tr><tr><td style="text-align:left;"><strong>Shadow Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduces the resolution of Shadow Maps.</td></tr><tr><td style="text-align:left;"><strong>Anti Aliasing</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Decreases anti-aliasing quality (MSAA) down to a complete disable.</td></tr><tr><td style="text-align:left;"><strong>LOD Bias</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Forces Unity to switch to low-poly LOD models at a closer distance from the camera.</td></tr><tr><td style="text-align:left;"><strong>Camera Clip</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduces the <code>Far Clip Plane</code> parameter on target cameras, culling distant objects from the render.</td></tr><tr><td style="text-align:left;"><strong>Layer Culling</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">Proportionally reduces the Culling Distance for specific object layers.</td></tr><tr><td style="text-align:left;"><strong>Physics Step</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">Lowers the frequency of physics calculations. Saves performance during heavy physics loads in the browser.</td></tr><tr><td style="text-align:left;"><strong>LUT</strong></td><td style="text-align:left;"><code>URP Only</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Reduces the size of Color Grading LUTs to the minimum.</td></tr><tr><td style="text-align:left;"><strong>Mesh LOD Threshold</strong></td><td style="text-align:left;"><code>Unity 6+</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Alters the <code>meshLodThreshold</code> parameter, introduced in Unity 6.2, for aggressive LOD switching.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Caution with Physics Step Scaler</p><p>The physics Scaler directly alters the <code>Time.fixedDeltaTime</code> parameter. If a character controller or game mechanic relies strictly on fixed physics frames without Interpolation, object movement may become stuttery at low quality levels.</p></div><div class="tip custom-block"><p class="custom-block-title">Resetting Scaler Settings</p><p>If you have experimented with Scaler parameters (e.g., modifying <code>Min Bound</code> or <code>Max Level</code>) and wish to revert them to defaults, simply toggle the switch off and back on in the <em>Project Settings</em> window. The plugin will automatically recreate the module with baseline settings.</p></div><h2 id="breakdown-resolution-scaler" tabindex="-1">Breakdown: Resolution Scaler <a class="header-anchor" href="#breakdown-resolution-scaler" aria-label="Permalink to &quot;Breakdown: Resolution Scaler&quot;">​</a></h2><p>This is the plugin&#39;s most powerful tool, providing the biggest FPS boost. Its operation varies drastically depending on the active pipeline.</p><h3 id="in-urp-mode-universal-render-pipeline" tabindex="-1">In URP Mode (Universal Render Pipeline) <a class="header-anchor" href="#in-urp-mode-universal-render-pipeline" aria-label="Permalink to &quot;In URP Mode (Universal Render Pipeline)&quot;">​</a></h3><p>In URP, scaling operates seamlessly. The plugin interfaces directly with the <code>renderScale</code> property within the <code>UniversalRenderPipelineAsset</code>. The interface (UI) remains crisp automatically, as URP is capable of rendering the Canvas over a scaled 3D world.</p><h3 id="in-birp-mode-built-in-render-pipeline" tabindex="-1">In BiRP Mode (Built-in Render Pipeline) <a class="header-anchor" href="#in-birp-mode-built-in-render-pipeline" aria-label="Permalink to &quot;In BiRP Mode (Built-in Render Pipeline)&quot;">​</a></h3><p>Historically, BiRP lacks a built-in Render Scale setting that functions in WebGL without breaking the interface or causing crashes (FBO Feedback Loop). WebAP resolves this by offering two exclusive strategies.</p><h4 id="mode-1-nativebrowserscaling" tabindex="-1">Mode 1: NativeBrowserScaling <a class="header-anchor" href="#mode-1-nativebrowserscaling" aria-label="Permalink to &quot;Mode 1: NativeBrowserScaling&quot;">​</a></h4><p>The plugin scales the HTML <code>&lt;canvas&gt;</code> element directly via Native Loop Spoofing (injecting into the browser&#39;s <code>devicePixelRatio</code> parameters).</p><ul><li><strong>Pros:</strong> Maximum performance, zero overhead on the GPU side.</li><li><strong>Cons:</strong> The game interface blurs alongside the 3D graphics. This mode only operates in a built WebGL build (no changes will be visible in the Unity Editor).</li></ul><h4 id="mode-2-rendertexturescaling" tabindex="-1">Mode 2: RenderTextureScaling <a class="header-anchor" href="#mode-2-rendertexturescaling" aria-label="Permalink to &quot;Mode 2: RenderTextureScaling&quot;">​</a></h4><p>The plugin redirects the render of target cameras into a compressed shared texture and utilizes a hidden Compositor Camera to display the image.</p><ul><li><strong>Pros:</strong> The 3D world is scaled, while the UI (text, buttons) remains crystal clear.</li><li><strong>Cons:</strong> Adds a marginal load to the GPU due to the Blit operation (copying the texture to the screen).</li></ul><div class="info custom-block"><p class="custom-block-title">Fixing Mouse Clicks (Raycasts)</p><p>When utilizing RenderTextureScaling, virtual screen coordinates are compressed. To ensure mouse clicks on 3D objects continue to function correctly, the plugin automatically replaces standard <code>PhysicsRaycaster</code> and <code>Physics2DRaycaster</code> components on target cameras with custom <code>WebScaledPhysicsRaycaster</code> components. Ray precision remains flawless at any scale.</p></div><h2 id="how-to-preserve-ui-clarity-for-birp-rendertexturescaling" tabindex="-1">How to Preserve UI Clarity? (For BiRP RenderTextureScaling) <a class="header-anchor" href="#how-to-preserve-ui-clarity-for-birp-rendertexturescaling" aria-label="Permalink to &quot;How to Preserve UI Clarity? (For BiRP RenderTextureScaling)&quot;">​</a></h2><p>To keep the interface crisp while scaling 3D graphics in BiRP with RenderTextureScaling, you must properly configure your Canvas. Select one of two options:</p><h3 id="option-1-screen-space-overlay-recommended" tabindex="-1">Option 1: Screen Space - Overlay (Recommended) <a class="header-anchor" href="#option-1-screen-space-overlay-recommended" aria-label="Permalink to &quot;Option 1: Screen Space - Overlay (Recommended)&quot;">​</a></h3><p>The simplest and most reliable method. The plugin handles all the work automatically.</p><ol><li>Select your <strong>Canvas</strong> in the scene hierarchy.</li><li>In the Canvas component, set the <strong>Render Mode</strong> to <code>Screen Space - Overlay</code>.<br><em>Result:</em> Unity renders the interface atop the compressed 3D world at 100% native resolution.</li></ol><h3 id="option-2-screen-space-camera-for-complex-layers" tabindex="-1">Option 2: Screen Space - Camera (For Complex Layers) <a class="header-anchor" href="#option-2-screen-space-camera-for-complex-layers" aria-label="Permalink to &quot;Option 2: Screen Space - Camera (For Complex Layers)&quot;">​</a></h3><p>Utilized if you need to blend 3D models, particles, and UI. You will need to separate the render across two cameras.</p><ol><li><strong>Main Camera (3D):</strong> Ensure its tag is specified in the Scaler&#39;s <code>Target Tags</code> array. In the <code>Culling Mask</code> field, uncheck the <strong>UI</strong> layer. Set <code>Depth</code> to <code>0</code>.</li><li><strong>UI Camera (New):</strong> Create a new camera to render the interface. <strong>Do not</strong> add its tag to the Scaler settings. <ul><li>Set <code>Clear Flags</code> to <code>Depth Only</code> (so the camera does not erase the 3D background).</li><li>Set <code>Culling Mask</code> exclusively to the <strong>UI</strong> layer.</li><li>Set <code>Depth</code> to <code>1</code> (higher than the main camera).</li></ul></li><li><strong>Canvas Configuration:</strong> Set the <strong>Render Mode</strong> to <code>Screen Space - Camera</code> and drag your new UI Camera into the <code>Render Camera</code> slot.</li></ol>',28)])])}const m=t(r,[["render",i]]);export{p as __pageData,m as default};
